def longest_common_substring(a,b):
    # dynamic programming O(n*m)
    n, m = len(a), len(b)
    dp = [[0]*(m+1) for _ in range(n+1)]
    best = 0
    best_end = (0,0)
    for i in range(1, n+1):
        for j in range(1, m+1):
            if a[i-1]==b[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
                if dp[i][j] > best:
                    best = dp[i][j]
                    best_end=(i,j)
            else:
                dp[i][j]=0
    return best, best_end

